file.content:
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Microsoft YaHei UI', -apple-system, BlinkMacSystemFont, sans-serif;
    overflow-y: auto;
    min-height: 100vh;
    background: #0a0a1a;
}

/* 极光渐变背景 */
.aurora-bg {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    z-index: -1;
    background: linear-gradient(135deg, #0a0a1a 0%, #1a0a2e 50%, #0a1a2e 100%);
}

.aurora-blob {
    position: absolute;
    border-radius: 50%;
    filter: blur(80px);
    opacity: 0.6;
    animation: float 20s ease-in-out infinite;
}

.blob-1 {
    width: 500px;
    height: 500px;
    background: linear-gradient(45deg, #ff6b9d, #c04868);
    top: -200px;
    left: -100px;
    animation-delay: 0s;
}

.blob-2 {
    width: 400px;
    height: 400px;
    background: linear-gradient(45deg, #8a2be2, #5d26c1);
    top: 50%;
    right: -150px;
    animation-delay: -5s;
}

.blob-3 {
    width: 450px;
    height: 450px;
    background: linear-gradient(45deg, #00c8ff, #06b6d4);
    bottom: -150px;
    left: 30%;
    animation-delay: -10s;
}

.blob-4 {
    width: 350px;
    height: 350px;
    background: linear-gradient(45deg, #ff6b9d, #8a2be2);
    top: 40%;
    left: 40%;
    animation-delay: -15s;
}

@keyframes float {
    0%, 100% {
        transform: translate(0, 0) scale(1);
    }
    25% {
        transform: translate(50px, -50px) scale(1.1);
    }
    50% {
        transform: translate(-30px, 30px) scale(0.9);
    }
    75% {
        transform: translate(-50px, -30px) scale(1.05);
    }
}

/* 主容器 */
.container {
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 25px 20px;
    min-height: 100vh;
    overflow-y: auto;
}

/* Logo 区域 */
.header {
    text-align: center;
    margin-bottom: 25px;
}

.logo-container {
    display: flex;
    justify-content: center;
    gap: 20px;
    margin-bottom: 15px;
}

.logo {
    width: 70px;
    height: 70px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.3);
}

.youtube-logo {
    background: linear-gradient(135deg, #ff0000, #cc0000);
}

.douyin-logo {
    background: linear-gradient(135deg, #00c8ff, #0099cc);
}

.logo svg {
    width: 35px;
    height: 35px;
}

.title {
    font-size: 32px;
    font-weight: bold;
    color: #ffffff;
    margin-bottom: 8px;
    text-shadow: 0 2px 20px rgba(255, 107, 157, 0.5);
}

.subtitle {
    font-size: 14px;
    color: #ff6b9d;
}

/* 玻璃拟态卡片 */
.glass-card {
    background: rgba(42, 26, 58, 0.6);
    backdrop-filter: blur(20px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 20px;
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.3);
}

.main-card {
    width: 100%;
    max-width: 520px;
    padding: 25px;
    margin-bottom: 20px;
    flex-shrink: 0;
}

/* 标签 */
.label {
    display: block;
    font-size: 13px;
    font-weight: bold;
    color: #ff6b9d;
    margin-bottom: 10px;
}

/* 输入区域 */
.input-section {
    margin-bottom: 20px;
}

.input-wrapper {
    display: flex;
    gap: 10px;
}

.url-input {
    flex: 1;
    padding: 14px 18px;
    font-size: 14px;
    background: rgba(26, 10, 42, 0.8);
    border: 1px solid rgba(255, 107, 157, 0.3);
    border-radius: 12px;
    color: #ffffff;
    outline: none;
    transition: all 0.3s ease;
}

.url-input:focus {
    border-color: #ff6b9d;
    box-shadow: 0 0 20px rgba(255, 107, 157, 0.3);
}

.url-input::placeholder {
    color: rgba(255, 255, 255, 0.4);
}

.paste-btn {
    width: 50px;
    height: 50px;
    font-size: 20px;
    background: linear-gradient(135deg, #8a2be2, #5d26c1);
    border: none;
    border-radius: 12px;
    cursor: pointer;
    transition: all 0.3s ease;
}

.paste-btn:hover {
    transform: scale(1.05);
    box-shadow: 0 5px 20px rgba(138, 43, 226, 0.4);
}

.platform-indicator {
    margin-top: 10px;
    font-size: 12px;
    color: rgba(255, 255, 255, 0.5);
}

/* 模式选择 */
.mode-section {
    margin-bottom: 20px;
}

.mode-buttons {
    display: flex;
    gap: 10px;
}

.mode-btn {
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 8px;
    padding: 15px 10px;
    background: rgba(255, 255, 255, 0.05);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 12px;
    cursor: pointer;
    transition: all 0.3s ease;
}

.mode-btn:hover {
    background: rgba(255, 255, 255, 0.1);
}

.mode-btn.active {
    background: linear-gradient(135deg, rgba(255, 107, 157, 0.3), rgba(138, 43, 226, 0.3));
    border-color: #ff6b9d;
}

.mode-icon {
    font-size: 24px;
}

.mode-text {
    font-size: 12px;
    color: #ffffff;
}

/* 进度条 */
.progress-section {
    margin-bottom: 20px;
}

.progress-bar {
    height: 10px;
    background: rgba(26, 10, 42, 0.8);
    border-radius: 10px;
    overflow: hidden;
    margin-bottom: 10px;
}

.progress-fill {
    height: 100%;
    width: 0%;
    background: linear-gradient(90deg, #ff6b9d, #8a2be2, #00c8ff);
    border-radius: 10px;
    transition: width 0.3s ease;
}

.status-text {
    font-size: 12px;
    color: rgba(255, 255, 255, 0.6);
    text-align: center;
}

/* 操作按钮 */
.action-buttons {
    display: flex;
    flex-direction: column;
    gap: 12px;
    margin-bottom: 15px;
}

.btn {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 12px;
    padding: 18px;
    font-size: 16px;
    font-weight: bold;
    border: none;
    border-radius: 14px;
    cursor: pointer;
    transition: all 0.3s ease;
}

.btn-icon {
    font-size: 20px;
}

.btn-text {
    color: #ffffff;
}

.btn-primary {
    background: linear-gradient(135deg, #ff3366, #ff6b9d);
    box-shadow: 0 4px 20px rgba(255, 51, 102, 0.4);
}

.btn-primary:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 30px rgba(255, 51, 102, 0.6);
}

.btn-info {
    background: linear-gradient(135deg, #00aacc, #06b6d4);
    box-shadow: 0 4px 20px rgba(0, 170, 204, 0.4);
}

.btn-info:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 30px rgba(0, 170, 204, 0.6);
}

.btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
    transform: none !important;
}

/* 信息框 */
.info-box {
    padding: 15px;
    background: rgba(26, 10, 42, 0.6);
    border-radius: 12px;
}

.info-box p {
    font-size: 12px;
    color: rgba(255, 255, 255, 0.5);
    line-height: 1.8;
    margin: 0;
}

/* 底部信息 */
.footer {
    font-size: 12px;
    color: rgba(255, 255, 255, 0.4);
    text-align: center;
}

/* 弹窗 */
.modal {
    display: none;
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.7);
    backdrop-filter: blur(5px);
    z-index: 1000;
    align-items: center;
    justify-content: center;
}

.modal.show {
    display: flex;
}

.modal-content {
    width: 90%;
    max-width: 500px;
    max-height: 80vh;
    overflow: auto;
}

.modal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 20px;
}

.modal-header h2 {
    font-size: 20px;
    color: #ff6b9d;
}

.close-btn {
    width: 35px;
    height: 35px;
    font-size: 18px;
    background: rgba(255, 255, 255, 0.1);
    border: none;
    border-radius: 50%;
    color: #ffffff;
    cursor: pointer;
    transition: all 0.3s ease;
}

.close-btn:hover {
    background: rgba(255, 107, 157, 0.5);
}

.modal-body {
    color: #ffffff;
    line-height: 1.8;
    font-size: 14px;
    white-space: pre-wrap;
}

/* 滚动条 */
::-webkit-scrollbar {
    width: 8px;
}

::-webkit-scrollbar-track {
    background: rgba(255, 255, 255, 0.05);
    border-radius: 10px;
}

::-webkit-scrollbar-thumb {
    background: rgba(255, 107, 157, 0.5);
    border-radius: 10px;
}

::-webkit-scrollbar-thumb:hover {
    background: rgba(255, 107, 157, 0.7);
}

